#include<bits/stdc++.h>
using namespace std;
const long long mod=19260817;
long long read()
{
    long long x=0;
    char ch=getchar();
    while(!isdigit(ch))
    {
        ch=getchar();
    }
    while(isdigit(ch))
    {
        x=((x*10%mod)+(ch-'0'))%mod;
        ch=getchar();
    }
    return x;
}
long long exgcd(long long &x,long long &y,long long a,long long b)
{
    if(b==0)
    {
        x=1;
        y=0;
        return a;
    }
    long long g=exgcd(x,y,b,a%b);
    long long tx=x;
    x=y;
    y=tx-(a/b)*y;
    return g;
}
int main()
{
    long long a=read(),b=read();
    if(b==0)
    {
        printf("Angry!");
        return 0;
    }
    long long x,y;
    exgcd(x,y,b,mod);
    printf("%lld",(x%mod+mod)%mod*a%mod);
    return 0;
}
